1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	  moonstone: 25,
11	};
12	
13	export function processScenario(input: any): unknown {
14	  const items = input.steps[0].items;
15	  if (items.length === 0) {
16	    return { results: [{ premium: PROCESSING_FEE }] };
17	  }
18	  const countsByType: Record<string, number> = {};
19	  for (const item of items) {
20	    countsByType[item.type] = (countsByType[item.type] ?? 0) + 1;
21	  }
22	  let basePremium = 0;
23	  for (const [type, count] of Object.entries(countsByType)) {
24	    if ((type === "rune" || type === "moonstone") && count === 3) {
25	      basePremium += 60;
26	    } else {
27	      basePremium += count * BASE_PREMIUM_BY_TYPE[type];
28	    }
29	  }
30	  let itemSurcharges = 0;
31	  for (const item of items) {
32	    if (item.cursed) {
33	      itemSurcharges += BASE_PREMIUM_BY_TYPE[item.type] * 0.5;
34	    }
35	    if (item.enchantment >= 5) {
36	      itemSurcharges += BASE_PREMIUM_BY_TYPE[item.type] * 0.3;
37	    }
38	  }
39	  const loyaltyDiscount = input.customer.yearsWithMHPCO >= 2 ? basePremium * 0.2 : 0;
40	  const premium = Math.ceil(basePremium + itemSurcharges + basePremium * FIRST_INSURANCE_RATE - loyaltyDiscount + PROCESSING_FEE);
41	  return { results: [{ premium }] };
42	}
